#include <stdio.h>
#include <string.h>
int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    char buf[256];
    // consume the newline after the integer
    fgets(buf, sizeof(buf), stdin);
    for (int i = 0; i < T; ++i) {
        // read and ignore the description line (may be empty)
        fgets(buf, sizeof(buf), stdin);
        printf("Mean imputation and regression imputation are two techniques used for handling missing data.\n");
        printf("They impact model performance by reducing bias and improving accuracy.\n");
    }
    return 0;
}

